class Solution:
    def freqAlphabets(self, s):
        import re
        tokens = re.findall(r'\d\d#|\d', s)
        res = []
        for t in tokens:
            num = int(t[:2]) if t.endswith('#') else int(t)
            res.append(chr(ord('a') + num - 1))
        return ''.join(res)

