class Solution:
    def freqAlphabets(self, s):
        res = []
        i = 0
        n = len(s)
        while i < n:
            if i + 2 < n and s[i + 2] == '#':
                num = int(s[i:i + 2])
                i += 3
            else:
                num = int(s[i])
                i += 1
            res.append(chr(ord('a') + num - 1))
        return ''.join(res)

