var freqAlphabets = function(s) {
    const res = [];
    let i = 0;
    const n = s.length;
    while (i < n) {
        let num;
        if (i + 2 < n && s[i + 2] === '#') {
            num = parseInt(s.slice(i, i + 2), 10);
            i += 3;
        } else {
            num = parseInt(s[i], 10);
            i += 1;
        }
        res.push(String.fromCharCode('a'.charCodeAt(0) + num - 1));
    }
    return res.join('');
};
